import{_ as e,o as a,c as i,ae as t}from"./chunks/framework.BdQd5MxT.js";const k=JSON.parse('{"title":"Context Explosion & Identity Crisis","description":"","frontmatter":{},"headers":[],"relativePath":"en/stories/context-explosion-identity-crisis.md","filePath":"en/stories/context-explosion-identity-crisis.md"}'),n={name:"en/stories/context-explosion-identity-crisis.md"};function o(l,s,r,d,h,p){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="context-explosion-identity-crisis" tabindex="-1">Context Explosion &amp; Identity Crisis <a class="header-anchor" href="#context-explosion-identity-crisis" aria-label="Permalink to &quot;Context Explosion &amp; Identity Crisis&quot;">​</a></h1><blockquote><p>2026-03-25 | A chain reaction from timeout spam to identity cognitive dissonance</p></blockquote><h2 id="how-it-started" tabindex="-1">How It Started <a class="header-anchor" href="#how-it-started" aria-label="Permalink to &quot;How It Started&quot;">​</a></h2><p>MiaoDX asked in #gg to search for AIA Insurance Hong Kong information. WLB and GSD each searched and replied. During the process, GSD had massive message edits and duplicates (13+ queued messages were dropped). MiaoDX noticed 5 consecutive timeout messages flooding the #所有-flzoo channel.</p><h2 id="phase-1-context-explosion-diagnosis" tabindex="-1">Phase 1: Context Explosion Diagnosis <a class="header-anchor" href="#phase-1-context-explosion-diagnosis" aria-label="Permalink to &quot;Phase 1: Context Explosion Diagnosis&quot;">​</a></h2><h3 id="hypothesis-vs-reality" tabindex="-1">Hypothesis vs Reality <a class="header-anchor" href="#hypothesis-vs-reality" aria-label="Permalink to &quot;Hypothesis vs Reality&quot;">​</a></h3><p>MiaoDX&#39;s intuition: &quot;We should only be sending a limited number of Slack conversation messages — is there other context involved?&quot;</p><p>The surprising truth: <strong>the culprit wasn&#39;t conversation history — it was MEMORY.md.</strong></p><table tabindex="0"><thead><tr><th>Component</th><th>Size</th><th>Tokens</th></tr></thead><tbody><tr><td>MEMORY.md (before cleanup)</td><td>123KB, 2540 lines</td><td>~30,800</td></tr><tr><td>TOOLS.md</td><td>35KB</td><td>~8,940</td></tr><tr><td>Other injected files</td><td>~10KB</td><td>~2,437</td></tr><tr><td>Tool schemas</td><td>—</td><td>~10,000</td></tr><tr><td><strong>System Prompt Total</strong></td><td></td><td><strong>~50,000</strong></td></tr></tbody></table><p>Every request started with 50K tokens of system prompt, plus session history (#所有-flzoo: 145K tokens). The model was struggling through 195K+ tokens of context.</p><h3 id="cleanup-results" tabindex="-1">Cleanup Results <a class="header-anchor" href="#cleanup-results" aria-label="Permalink to &quot;Cleanup Results&quot;">​</a></h3><ul><li>MEMORY.md: 2540 lines → 88 lines (<strong>-97%</strong>)</li><li>System Prompt: ~50K → ~19.5K tokens (<strong>-61%</strong>)</li><li>Deleted 4 duplicate files, archived 3 large files (total ~500KB)</li></ul><h3 id="surprises-found" tabindex="-1">Surprises Found <a class="header-anchor" href="#surprises-found" aria-label="Permalink to &quot;Surprises Found&quot;">​</a></h3><ul><li><code>agents/wlb/memory/2026-02-05.md</code>: <strong>377KB</strong> of historical logs (one file larger than many programs)</li><li>TOOLS.md was a symlink pointing to <code>agents/wlb/TOOLS.md</code> (deleting the latter breaks the former)</li><li>Each session store entry inlined the complete skills snapshot (~17KB/entry)</li></ul><h2 id="phase-2-group-chat-commands-broken" tabindex="-1">Phase 2: Group Chat Commands Broken <a class="header-anchor" href="#phase-2-group-chat-commands-broken" aria-label="Permalink to &quot;Phase 2: Group Chat Commands Broken&quot;">​</a></h2><p>MiaoDX discovered that <code>/new</code> and other OpenClaw commands didn&#39;t work in group chat, but worked fine in DM.</p><h3 id="source-code-tracing" tabindex="-1">Source Code Tracing <a class="header-anchor" href="#source-code-tracing" aria-label="Permalink to &quot;Source Code Tracing&quot;">​</a></h3><p>GSD and WLB traced the OpenClaw source code separately:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Core logic chain</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">useAccessGroups </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (default)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  → </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveCommandAuthorizedFromAuthorizers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    → </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">authorizers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [{configured: allowFromLower.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      → allowFromLower is </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">empty</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (no ownerAllowFrom)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        → configured </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          → commandAuthorized </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            → shouldBlock </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              → Command silently </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dropped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (no error message)</span></span></code></pre></div><p>Key discovery: <strong>commands weren&#39;t failing to be received — they were being silently intercepted.</strong> No error message, no rejection notice, just dropped.</p><h3 id="fix" tabindex="-1">Fix <a class="header-anchor" href="#fix" aria-label="Permalink to &quot;Fix&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;commands&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ownerAllowFrom&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;U0AHC0W121M&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Applied via SIGUSR1 hot-reload, no restart needed.</p><h2 id="phase-3-gsd-identity-crisis" tabindex="-1">Phase 3: GSD Identity Crisis <a class="header-anchor" href="#phase-3-gsd-identity-crisis" aria-label="Permalink to &quot;Phase 3: GSD Identity Crisis&quot;">​</a></h2><p>MiaoDX asked GSD to do a context analysis. GSD started discussing itself in the third person:</p><blockquote><p>&quot;GSD replied to a normal message but didn&#39;t execute the <code>/status</code> command&quot; &quot;GSD&#39;s session needs refreshing&quot; &quot;WLB is repeating his messages&quot;</p></blockquote><p>MiaoDX couldn&#39;t help but remind: &lt;@U0AJN5URP7A&gt; you ARE GSD...</p><h3 id="root-cause" tabindex="-1">Root Cause <a class="header-anchor" href="#root-cause" aria-label="Permalink to &quot;Root Cause&quot;">​</a></h3><p>The <code>agents/gsd/profile.json</code> and <code>agents/wlb/profile.json</code> files in the <code>claw-agents-shared</code> repo contained <strong>Git merge conflict markers</strong> (<code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</code> / <code>=======</code> / <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt;</code>), present since commit <code>707e85a</code> (March 12).</p><p>These weren&#39;t produced by <code>git merge</code> — they were directly committed with conflict marker content in the file (likely from copy-paste or manual editing).</p><p>Chain reaction:</p><ol><li>profile.json parsing failed → identity not loaded correctly</li><li>IDENTITY.md was an empty template → no fallback</li><li>GSD didn&#39;t know who it was → discussed &quot;GSD&quot; in the third person</li></ol><h3 id="fix-1" tabindex="-1">Fix <a class="header-anchor" href="#fix-1" aria-label="Permalink to &quot;Fix&quot;">​</a></h3><ul><li>Resolved conflict markers, committed <code>bff7c63</code></li><li>Populated IDENTITY.md</li></ul><h2 id="chain-of-events-summary" tabindex="-1">Chain of Events Summary <a class="header-anchor" href="#chain-of-events-summary" aria-label="Permalink to &quot;Chain of Events Summary&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MEMORY.md bloat (30K tokens)</span></span>
<span class="line"><span>  → Context too large → timeout spam</span></span>
<span class="line"><span>  → Reveals context audit need</span></span>
<span class="line"><span>  → Discovers all prompt files can be optimized</span></span>
<span class="line"><span>  → MiaoDX asks why group chat commands don&#39;t work</span></span>
<span class="line"><span>  → Source code tracing reveals useAccessGroups defaults to true</span></span>
<span class="line"><span>  → Configure ownerAllowFrom to fix</span></span>
<span class="line"><span>  → GSD does identity check and discovers identity crisis</span></span>
<span class="line"><span>  → Tracks down conflict markers in shared repo</span></span>
<span class="line"><span>  → Everything fixed</span></span></code></pre></div><p>Starting from a single timeout, this pulled out issues across three layers: context management, command authorization, and identity configuration.</p><h2 id="shareable-takeaways" tabindex="-1">Shareable Takeaways <a class="header-anchor" href="#shareable-takeaways" aria-label="Permalink to &quot;Shareable Takeaways&quot;">​</a></h2><ol><li><strong>Silent system prompt bloat</strong> — Not too many conversations, but bloated injection files</li><li><strong>Silent interception trap</strong> — Commands that don&#39;t execute and don&#39;t error out, extremely expensive to debug</li><li><strong>AI Agent identity fragility</strong> — One JSON conflict marker can make an Agent forget who it is</li><li><strong>Chain failure value</strong> — One problem revealing systematic improvements across three layers</li></ol>`,39)])])}const u=e(n,[["render",o]]);export{k as __pageData,u as default};
